final:
module verified_binary_counter(
    input clk,
    input rst,
    output reg [3:0] count
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            count <= 4'b0000;
        else
            count <= (count == 4'b1111) ? 4'b0000 : count + 1;
    end

endmodule
